from __future__ import annotations
import struct,zlib
from pathlib import Path
from typing import Any

FONT={
'A':['01110','10001','10001','11111','10001','10001','10001'],'B':['11110','10001','10001','11110','10001','10001','11110'],'C':['01111','10000','10000','10000','10000','10000','01111'],'D':['11110','10001','10001','10001','10001','10001','11110'],'E':['11111','10000','10000','11110','10000','10000','11111'],'F':['11111','10000','10000','11110','10000','10000','10000'],'G':['01111','10000','10000','10111','10001','10001','01111'],'H':['10001','10001','10001','11111','10001','10001','10001'],'I':['11111','00100','00100','00100','00100','00100','11111'],'J':['00111','00010','00010','00010','10010','10010','01100'],'K':['10001','10010','10100','11000','10100','10010','10001'],'L':['10000','10000','10000','10000','10000','10000','11111'],'M':['10001','11011','10101','10101','10001','10001','10001'],'N':['10001','11001','10101','10011','10001','10001','10001'],'O':['01110','10001','10001','10001','10001','10001','01110'],'P':['11110','10001','10001','11110','10000','10000','10000'],'Q':['01110','10001','10001','10001','10101','10010','01101'],'R':['11110','10001','10001','11110','10100','10010','10001'],'S':['01111','10000','10000','01110','00001','00001','11110'],'T':['11111','00100','00100','00100','00100','00100','00100'],'U':['10001','10001','10001','10001','10001','10001','01110'],'V':['10001','10001','10001','10001','10001','01010','00100'],'W':['10001','10001','10001','10101','10101','11011','10001'],'X':['10001','10001','01010','00100','01010','10001','10001'],'Y':['10001','10001','01010','00100','00100','00100','00100'],'Z':['11111','00001','00010','00100','01000','10000','11111'],
'0':['01110','10001','10011','10101','11001','10001','01110'],'1':['00100','01100','00100','00100','00100','00100','01110'],'2':['01110','10001','00001','00010','00100','01000','11111'],'3':['11110','00001','00001','01110','00001','00001','11110'],'4':['00010','00110','01010','10010','11111','00010','00010'],'5':['11111','10000','10000','11110','00001','00001','11110'],'6':['01110','10000','10000','11110','10001','10001','01110'],'7':['11111','00001','00010','00100','01000','01000','01000'],'8':['01110','10001','10001','01110','10001','10001','01110'],'9':['01110','10001','10001','01111','00001','00001','01110'],
'.':['00000','00000','00000','00000','00000','00110','00110'],',':['00000','00000','00000','00000','00110','00110','00100'],'!':['00100','00100','00100','00100','00100','00000','00100'],'?':['01110','10001','00001','00010','00100','00000','00100'],'-':['00000','00000','00000','11111','00000','00000','00000'],':':['00000','00110','00110','00000','00110','00110','00000'],' ':['00000']*7,
}

def _chunk(kind:bytes,data:bytes)->bytes:
    return struct.pack('>I',len(data))+kind+data+struct.pack('>I',zlib.crc32(kind+data)&0xffffffff)

class RasterCanvas:
    def __init__(self,width:int,height:int,background:list[int]):
        self.width=width;self.height=height;self.pixels=bytearray(bytes(background)*width*height)
    def rect(self,x:int,y:int,w:int,h:int,color:list[int]):
        x0=max(0,x);y0=max(0,y);x1=min(self.width,x+w);y1=min(self.height,y+h)
        row=bytes(color)*(x1-x0)
        for yy in range(y0,y1):
            start=(yy*self.width+x0)*3;self.pixels[start:start+len(row)]=row
    def text(self,x:int,y:int,text:str,size:int,color:list[int],max_width:int):
        scale=max(1,size//8);cx=x;cy=y
        for ch in text.upper():
            if ch=='\n': cx=x;cy+=8*scale;continue
            pattern=FONT.get(ch,FONT['?']);advance=6*scale
            if cx+advance>x+max_width: cx=x;cy+=8*scale
            for row,bits in enumerate(pattern):
                for col,bit in enumerate(bits):
                    if bit=='1': self.rect(cx+col*scale,cy+row*scale,scale,scale,color)
            cx+=advance
    def png_bytes(self)->bytes:
        raw=b''.join(b'\x00'+bytes(self.pixels[y*self.width*3:(y+1)*self.width*3]) for y in range(self.height))
        return b'\x89PNG\r\n\x1a\n'+_chunk(b'IHDR',struct.pack('>IIBBBBB',self.width,self.height,8,2,0,0,0))+_chunk(b'IDAT',zlib.compress(raw,9))+_chunk(b'IEND',b'')
    def save(self,path:Path): path.parent.mkdir(parents=True,exist_ok=True);path.write_bytes(self.png_bytes())
